async function getLatestVersion() {
  try {
    const response = await fetch('https://api.github.com/repos/jerryzmtz/my-tavern-scripts/tags');
    const tags = await response.json();
    return tags[0]?.name || 'main';
  } catch {
    return 'main';
  }
}

const version = await getLatestVersion();
await import(`https://testingcf.jsdelivr.net/gh/jerryzmtz/my-tavern-scripts@${version}/dist/骰子系统/stable.js`);

// ===== ACU Color Patch: Colorize dice outcome names in chat =====
(function(){
  const s=document.createElement('style');
  s.textContent='.acu-gold{color:#FFD700;font-weight:bold}.acu-orange{color:#FF6600;font-weight:bold}.acu-red{color:#FF0000;font-weight:bold}.acu-green{color:#27ae60;font-weight:bold}';
  document.head.appendChild(s);

  const re=/(—\s*)(暴击|暴击失败|大失败|成功|失败)(?!<)/g;
  const map={'暴击':'acu-gold','暴击失败':'acu-orange','大失败':'acu-red','成功':'acu-green','失败':'acu-red'};

  function colorize(el){
    const h=el.innerHTML;if(!h.includes('⚡'))return;
    const r=h.replace(re,(m,p,n)=>p+'<span class="'+map[n]+'">'+n+'</span>');
    if(r!==h)el.innerHTML=r;
  }

  function waitForChat(){
    const chat=document.getElementById('chat')||document.querySelector('.chat')||document.querySelector('[class*="chat"]');
    if(!chat){setTimeout(waitForChat,500);return}
    chat.querySelectorAll('.mes_text').forEach(colorize);
    new MutationObserver(function(mutations){
      mutations.forEach(function(m){
        m.addedNodes.forEach(function(n){
          if(n.nodeType!==1)return;
          var e=n.matches('.mes_text')?n:n.querySelector('.mes_text');
          if(e)colorize(e);
        });
      });
    }).observe(chat,{childList:true,subtree:true});
  }
  waitForChat();
})();
